'use client'

import { useState } from 'react'
import { motion } from 'framer-motion'
import { PlusCircle, CheckCircle, AlertCircle, Upload, Mail, Phone, MapPin } from 'lucide-react'
import { EtherealHero } from '@/components/ui/ethereal-hero'

const categories = [
  'Education',
  'Health & Wellness',
  'Career & Jobs',
  'Volunteering',
  'Community Projects',
  'Food & Nutrition',
  'Housing & Shelter',
  'Legal Services',
  'Mental Health',
  'Youth Programs',
  'Senior Services',
  'Other',
]

export default function SubmitPage() {
  const [formData, setFormData] = useState({
    name: '',
    organization: '',
    email: '',
    phone: '',
    category: '',
    website: '',
    description: '',
    address: '',
    hours: '',
  })
  const [isSubmitted, setIsSubmitted] = useState(false)
  const [isLoading, setIsLoading] = useState(false)

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    setIsLoading(true)
    
    // Simulate form submission
    await new Promise(resolve => setTimeout(resolve, 1500))
    
    setIsLoading(false)
    setIsSubmitted(true)
  }

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    setFormData(prev => ({
      ...prev,
      [e.target.name]: e.target.value
    }))
  }

  if (isSubmitted) {
    return (
      <>
        <EtherealHero>
          <motion.div
            initial={{ scale: 0 }}
            animate={{ scale: 1 }}
            transition={{ duration: 0.5, type: 'spring' }}
            className="w-24 h-24 rounded-full bg-green-pale/20 border-4 border-green-pale flex items-center justify-center mx-auto mb-6"
          >
            <CheckCircle className="w-12 h-12 text-green-pale" />
          </motion.div>
          
          <motion.h1
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.2 }}
            className="font-space text-4xl font-bold text-white mb-4"
          >
            Thank You!
          </motion.h1>
          
          <motion.p
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.3 }}
            className="font-outfit text-lg text-white/75 mb-8"
          >
            Your resource submission has been received. Our team will review it within 2-3 business days and add it to the directory.
          </motion.p>

          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.4 }}
            className="flex gap-4 justify-center flex-wrap"
          >
            <a href="/" className="btn-primary px-6 py-3 rounded-xl font-outfit font-semibold">
              Return Home
            </a>
            <a href="/resources" className="btn-outline px-6 py-3 rounded-xl font-outfit font-semibold">
              Browse Resources
            </a>
          </motion.div>
        </EtherealHero>
      </>
    )
  }

  return (
    <>
      {/* Hero */}
      <section className="relative min-h-screen flex items-center justify-center overflow-hidden bg-gradient-to-br from-green-deep via-green-mid to-green-light pt-20">
        <div className="absolute inset-0 opacity-30">
          <div className="absolute inset-0 bg-[radial-gradient(ellipse_at_20%_30%,rgba(145,176,138,0.3)_0%,transparent_55%),radial-gradient(ellipse_at_80%_70%,rgba(45,74,40,0.6)_0%,transparent_50%)]" />
        </div>

        {/* Floating shapes */}
        <div className="absolute inset-0 pointer-events-none">
          <div className="absolute top-[-80px] right-[10%] w-[300px] h-[300px] rounded-full bg-white/5 animate-orb-float" style={{ animationDuration: '20s' }} />
          <div className="absolute bottom-[-40px] left-[8%] w-[180px] h-[180px] rounded-full bg-white/5 animate-orb-float" style={{ animationDuration: '15s', animationDelay: '-5s' }} />
        </div>

        <div className="relative z-10 text-center px-4 max-w-3xl mx-auto">
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6 }}
            className="inline-flex items-center gap-2 bg-white/10 border border-white/20 rounded-full px-4 py-1.5 mb-6"
          >
            <span className="w-1.5 h-1.5 rounded-full bg-green-pale animate-pulse" />
            <span className="text-xs font-bold text-white/90 tracking-wider uppercase">Community Driven</span>
          </motion.div>
          
          <motion.h1
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6, delay: 0.1 }}
            className="font-space text-5xl md:text-6xl font-bold text-white leading-tight mb-4"
          >
            Submit a Resource
          </motion.h1>
          
          <motion.p
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6, delay: 0.2 }}
            className="font-outfit text-lg text-white/75"
          >
            Know of a program that helped you or someone you know? Share it with our community so others can benefit too.
          </motion.p>
        </div>
      </section>

      {/* Form Section */}
      <section className="py-24 bg-[var(--section-bg)]">
        <div className="max-w-3xl mx-auto px-4">
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true }}
            className="bg-white rounded-[var(--radius-lg)] border border-green-wash shadow-card p-8 md:p-10"
          >
            {/* Info Banner */}
            <div className="bg-green-mist border border-green-wash rounded-[var(--radius-md)] p-4 mb-8 flex items-start gap-3">
              <AlertCircle className="w-5 h-5 text-green-mid flex-shrink-0 mt-0.5" />
              <div className="font-outfit text-sm text-[var(--text-body)]">
                <strong className="text-[var(--text-dark)]">All submissions are reviewed</strong> by our team within 2-3 business days to ensure quality and accuracy before being added to the directory.
              </div>
            </div>

            <form onSubmit={handleSubmit} className="space-y-6">
              {/* Resource Name */}
              <div>
                <label htmlFor="name" className="block font-outfit text-sm font-semibold text-[var(--text-dark)] mb-2">
                  Resource Name <span className="text-red-500">*</span>
                </label>
                <input
                  type="text"
                  id="name"
                  name="name"
                  required
                  value={formData.name}
                  onChange={handleChange}
                  placeholder="e.g., Bothell Food Bank"
                  className="w-full px-5 py-3 rounded-[var(--radius-md)] border-2 border-green-wash font-outfit text-sm outline-none focus:border-green-light transition-colors"
                />
              </div>

              {/* Organization */}
              <div>
                <label htmlFor="organization" className="block font-outfit text-sm font-semibold text-[var(--text-dark)] mb-2">
                  Organization / Provider Name
                </label>
                <input
                  type="text"
                  id="organization"
                  name="organization"
                  value={formData.organization}
                  onChange={handleChange}
                  placeholder="e.g., Bothell Community Services"
                  className="w-full px-5 py-3 rounded-[var(--radius-md)] border-2 border-green-wash font-outfit text-sm outline-none focus:border-green-light transition-colors"
                />
              </div>

              {/* Category */}
              <div>
                <label htmlFor="category" className="block font-outfit text-sm font-semibold text-[var(--text-dark)] mb-2">
                  Category <span className="text-red-500">*</span>
                </label>
                <select
                  id="category"
                  name="category"
                  required
                  value={formData.category}
                  onChange={handleChange}
                  className="w-full px-5 py-3 rounded-[var(--radius-md)] border-2 border-green-wash font-outfit text-sm outline-none focus:border-green-light transition-colors bg-white"
                >
                  <option value="">Select a category</option>
                  {categories.map(cat => (
                    <option key={cat} value={cat}>{cat}</option>
                  ))}
                </select>
              </div>

              {/* Description */}
              <div>
                <label htmlFor="description" className="block font-outfit text-sm font-semibold text-[var(--text-dark)] mb-2">
                  Description <span className="text-red-500">*</span>
                </label>
                <textarea
                  id="description"
                  name="description"
                  required
                  rows={4}
                  value={formData.description}
                  onChange={handleChange}
                  placeholder="Describe the resource, who it's for, and what services it provides..."
                  className="w-full px-5 py-3 rounded-[var(--radius-md)] border-2 border-green-wash font-outfit text-sm outline-none focus:border-green-light transition-colors resize-none"
                />
              </div>

              {/* Contact Info Row */}
              <div className="grid md:grid-cols-2 gap-6">
                <div>
                  <label htmlFor="email" className="block font-outfit text-sm font-semibold text-[var(--text-dark)] mb-2">
                    Email <span className="text-red-500">*</span>
                  </label>
                  <div className="relative">
                    <Mail className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-green-light" />
                    <input
                      type="email"
                      id="email"
                      name="email"
                      required
                      value={formData.email}
                      onChange={handleChange}
                      placeholder="contact@organization.org"
                      className="w-full pl-12 pr-5 py-3 rounded-[var(--radius-md)] border-2 border-green-wash font-outfit text-sm outline-none focus:border-green-light transition-colors"
                    />
                  </div>
                </div>
                <div>
                  <label htmlFor="phone" className="block font-outfit text-sm font-semibold text-[var(--text-dark)] mb-2">
                    Phone
                  </label>
                  <div className="relative">
                    <Phone className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-green-light" />
                    <input
                      type="tel"
                      id="phone"
                      name="phone"
                      value={formData.phone}
                      onChange={handleChange}
                      placeholder="(123) 456-7890"
                      className="w-full pl-12 pr-5 py-3 rounded-[var(--radius-md)] border-2 border-green-wash font-outfit text-sm outline-none focus:border-green-light transition-colors"
                    />
                  </div>
                </div>
              </div>

              {/* Address */}
              <div>
                <label htmlFor="address" className="block font-outfit text-sm font-semibold text-[var(--text-dark)] mb-2">
                  Address
                </label>
                <div className="relative">
                  <MapPin className="absolute left-4 top-4 w-4 h-4 text-green-light" />
                  <input
                    type="text"
                    id="address"
                    name="address"
                    value={formData.address}
                    onChange={handleChange}
                    placeholder="123 Main St, Bothell, WA 98011"
                    className="w-full pl-12 pr-5 py-3 rounded-[var(--radius-md)] border-2 border-green-wash font-outfit text-sm outline-none focus:border-green-light transition-colors"
                  />
                </div>
              </div>

              {/* Hours & Website Row */}
              <div className="grid md:grid-cols-2 gap-6">
                <div>
                  <label htmlFor="hours" className="block font-outfit text-sm font-semibold text-[var(--text-dark)] mb-2">
                    Hours of Operation
                  </label>
                  <input
                    type="text"
                    id="hours"
                    name="hours"
                    value={formData.hours}
                    onChange={handleChange}
                    placeholder="Mon-Fri 9am-5pm"
                    className="w-full px-5 py-3 rounded-[var(--radius-md)] border-2 border-green-wash font-outfit text-sm outline-none focus:border-green-light transition-colors"
                  />
                </div>
                <div>
                  <label htmlFor="website" className="block font-outfit text-sm font-semibold text-[var(--text-dark)] mb-2">
                    Website
                  </label>
                  <input
                    type="url"
                    id="website"
                    name="website"
                    value={formData.website}
                    onChange={handleChange}
                    placeholder="https://organization.org"
                    className="w-full px-5 py-3 rounded-[var(--radius-md)] border-2 border-green-wash font-outfit text-sm outline-none focus:border-green-light transition-colors"
                  />
                </div>
              </div>

              {/* Submit Button */}
              <button
                type="submit"
                disabled={isLoading}
                className="w-full bg-gradient-to-r from-green-mid to-green-pale text-white font-outfit font-semibold px-8 py-4 rounded-[var(--radius-md)] flex items-center justify-center gap-2 transition-all hover:shadow-lg hover:shadow-green-mid/30 disabled:opacity-70 disabled:cursor-not-allowed"
              >
                {isLoading ? (
                  <>
                    <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                    Submitting...
                  </>
                ) : (
                  <>
                    <Upload size={18} />
                    Submit Resource
                  </>
                )}
              </button>
            </form>
          </motion.div>
        </div>
      </section>
    </>
  )
}

